function asbab_for(int $s, int $a): ?string {
    global $ASBAB_NUZUL;
    return $ASBAB_NUZUL["$s:$a"] ?? null;
}

function asbab_indices_for_surah(int $s): array {
    global $ASBAB_NUZUL;
    $out = [];
    foreach ($ASBAB_NUZUL as $k => $_) {
        [$ks, $ka] = explode(':', $k);
        if ((int)$ks === $s) $out[] = (int)$ka;
    }
    return $out;
}
